import React, { useLayoutEffect, useState } from "react";
import { getHealthRecordInfoData } from "../../../../../api";
import { useSetRecoilState } from "recoil";
import { Notification } from "../../../../../modules/global/global-states";
import axios from "axios";

type healthRecordInfo = {
  id: number;
  serial: string;
  assetNumber: string;
  failure: string;
  resolution: string;
  completionDate: string;
  completionTime: string;
  result: string;
  taskNumber: string;
  workOrder: string;
  haWorkRequest: string;
  oldFilename: string;
  newFilename: string;
  dateCreated: string;
  completed: string;
};

export function useEquipmentHealthRecordHistoryTableHooks() {
  const setNotification = useSetRecoilState(Notification);
  const [healthRecordInfoData, setHealthRecordInfoData] = useState<
    healthRecordInfo[]
  >([]);

  useLayoutEffect(() => {
    getHealthRecordInfoData()
      .then((res) => {
        setHealthRecordInfoData(res);
      })
      .catch((err) => {
        setNotification({
          title: "Error fetching Equipment Health Record History data",
          message: JSON.stringify(err),
          level: 2,
        });
      });
  }, [setNotification]);

  return healthRecordInfoData;
}
